@ARTICLE{10.1016/j.celrep.2025.116658,
	author = {Wang G and Feng C and Ma Z and Zhao L and Yosri M and Wang Y and Gao X and Zhu W and Li H and Song H and Xia J and Meng M and Lu H and Zhang L and Chen Z and Sun D},
	title = {In toto imaging shows intravascular proliferation promotes transmigration of daughter cells during brain invasion of Cryptococcus neoformans.},
	journal = {Cell Rep},
	year = {2025},
	abstract = {Cryptococcus neoformans causes lethal meningoencephalitis. Although the mechanism of its blood-brain barrier (BBB) transmigration has been intensively studied, the predominant route remains unclear. We developed fTRACE, a whole-organ imaging workflow enabling in toto visualization of individual fungal cells in vivo, and found that C. neoformans can proliferate intravascularly before BBB transmigration. Importantly, daughter cells, not mother cells, predominantly transmigrate across the BBB. Intravascular proliferation depends on de novo purine biosynthesis. We created a non-proliferative fluorescent mutant to trace fungal fate in the brain and found that the majority of non-proliferative C. neoformans remained intravascular after prolonged brain infection, while the remainder induced local capillary pruning. Angiophagy occurred with low frequency. C. neoformans can be washed out from the brain vasculature, which is expedited by VEGFR-2 inhibition. This study elucidates a major brain invasion route of C. neoformans and provides an approach for studying host-pathogen interactions using in toto imaging.},
	doi = {10.1016/j.celrep.2025.116658},
	pmid = {41351837 [Indexed for MEDLINE]}
}

@ARTICLE{10.1126/sciadv.abb8783,
	author = {Li Z and Kim KS},
	title = {RELATe enables genome-scale engineering in fungal genomics.},
	journal = {Sci Adv},
	year = {2020},
	abstract = {CRISPR-Cas9-based screening with single-guide RNA (sgRNA) libraries has emerged as a revolutionary tool for comprehensive analysis of genetic elements. However, genome-scale sgRNA libraries are currently available only in a few model organisms. The traditional approach is to synthesize thousands to tens of thousands of sgRNAs, which is laborious and expensive. We have developed a simple method, RELATe (restriction/ligation coupled with Agrobacterium-mediated transformation), to generate sgRNA libraries from 10 μg of genomic DNA, targeting over 98% of the protein-coding genes in the human fungal pathogen Cryptococcus neoformans Functional screens identified 142 potential C. neoformans genes contributing to blood-brain barrier penetration. We selected two cryptococcal genes, SFP1 and WDR1, for a proof-of-concept demonstration that RELATe-identified genes are relevant to C. neoformans central nervous system infection. Our RELATe method can be used in many other fungal species and is powerful and cost-effective for genome-wide high-throughput screening for elucidating functional genomics.},
	doi = {10.1126/sciadv.abb8783},
	pmid = {32948588 [Indexed for MEDLINE]},
	note = {PMC7500931}
}

@ARTICLE{10.1038/s41467-020-18028-0,
	author = {Jin JH and Lee KT and Hong J and Lee D and Jang EH and Kim JY and Lee Y and Lee SH and So YS and Jung KW and Lee DG and Jeong E and Lee M and Jang YB and Choi Y and Lee MH and Kim JS and Yu SR and Choi JT and La JW and Choi H and Kim SW and Seo KJ and Lee Y and Thak EJ and Choi J and Averette AF and Lee YH and Heitman J and Kang HA and Cheong E and Bahn YS},
	title = {Genome-wide functional analysis of phosphatases in the pathogenic fungus Cryptococcus neoformans.},
	journal = {Nat Commun},
	year = {2020},
	abstract = {Phosphatases, together with kinases and transcription factors, are key components in cellular signalling networks. Here, we present a systematic functional analysis of the phosphatases in Cryptococcus neoformans, a fungal pathogen that causes life-threatening fungal meningoencephalitis. We analyse 230 signature-tagged mutant strains for 114 putative phosphatases under 30 distinct in vitro growth conditions, revealing at least one function for 60 of these proteins. Large-scale virulence and infectivity assays using insect and mouse models indicate roles in pathogenicity for 31 phosphatases involved in various processes such as thermotolerance, melanin and capsule production, stress responses, O-mannosylation, or retromer function. Notably, phosphatases Xpp1, Ssu72, Siw14, and Sit4 promote blood-brain barrier adhesion and crossing by C. neoformans. Together with our previous systematic studies of transcription factors and kinases, our results provide comprehensive insight into the pathobiological signalling circuitry of C. neoformans.},
	doi = {10.1038/s41467-020-18028-0},
	pmid = {32839469 [Indexed for MEDLINE]},
	note = {PMC7445287}
}

@ARTICLE{10.1038/s41467-020-15329-2,
	author = {Lee KT and Hong J and Lee DG and Lee M and Cha S and Lim YG and Jung KW and Hwangbo A and Lee Y and Yu SJ and Chen YL and Lee JS and Cheong E and Bahn YS},
	title = {Fungal kinases and transcription factors regulating brain infection in Cryptococcus neoformans.},
	journal = {Nat Commun},
	year = {2020},
	abstract = {Cryptococcus neoformans causes fatal fungal meningoencephalitis. Here, we study the roles played by fungal kinases and transcription factors (TFs) in blood-brain barrier (BBB) crossing and brain infection in mice. We use a brain infectivity assay to screen signature-tagged mutagenesis (STM)-based libraries of mutants defective in kinases and TFs, generated in the C. neoformans H99 strain. We also monitor in vivo transcription profiles of kinases and TFs during host infection using NanoString technology. These analyses identify signalling components involved in BBB adhesion and crossing, or survival in the brain parenchyma. The TFs Pdr802, Hob1, and Sre1 are required for infection under all the conditions tested here. Hob1 controls the expression of several factors involved in brain infection, including inositol transporters, a metalloprotease, PDR802, and SRE1. However, Hob1 is dispensable for most cellular functions in Cryptococcus deuterogattii R265, a strain that does not target the brain during infection. Our results indicate that Hob1 is a master regulator of brain infectivity in C. neoformans.},
	doi = {10.1038/s41467-020-15329-2},
	pmid = {32251295 [Indexed for MEDLINE]},
	note = {PMC7090016}
}
